// 全局背包
var dp = vector<int>(m + 1);
dp[0] = 1;
fa(i, 1, n)fa(j, a[i], m)dp[j] = (dp[j] + dp[j - a[i]]) % mod;

// 【撤销 a[i]】
// 原理：dp_without[j] = dp_with[j] - dp_with[j-w]
// 倒序意味着 dp[j] 实际上就减了 dp[j - w] 这个代表装了 a[i] 的方案数一次
fb(j, m, a[i])dp[j] = ((dp[j] - dp[j - a[i]]) % mod + mod) % mod;

// 【恢复 a[i]】
fa(j, a[i], m)dp[j] = (dp[j] + dp[j - a[i]]) % mod;
